const crypto = require('crypto');
const https = require('https');

const appId = $env.GITHUB_APP_ID;
const installationId = $env.GITHUB_INSTALLATION_ID;
const privateKeyBase64 = $env.GITHUB_PRIVATE_KEY_BASE64;
const privateKey = Buffer.from(privateKeyBase64, 'base64').toString('utf8');

const now = Math.floor(Date.now() / 1000);
const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
const payload = Buffer.from(JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId })).toString('base64url');
const signature = crypto.sign('SHA256', Buffer.from(`${header}.${payload}`), privateKey).toString('base64url');
const jwt = `${header}.${payload}.${signature}`;

const token = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.github.com',
    path: `/app/installations/${installationId}/access_tokens`,
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${jwt}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'Content-Length': 0
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => {
      if (res.statusCode !== 201) reject(new Error(`GitHub token request failed: ${res.statusCode} ${body}`));
      else resolve(JSON.parse(body).token);
    });
  });
  req.on('error', reject);
  req.end();
});

return [{ json: { ...$input.first().json, githubToken: token } }];

const https = require('https');
const input = $input.first().json;
const token = input.githubToken;
const owner = input.repoOwner;
const repo = input.repoName;
const storyNumber = input.storyNumber;
const storyTitle = input.storyTitle;
const storyDescription = input.storyDescription;
const epicTitle = input.epicTitle;
const epicNumber = input.epicNumber;
const dependencyTitles = input.dependencyTitles || 'none';
const gdd = input.gdd || '';
const projectContext = input.projectContext || '';
const epicComments = input.epicComments || '';
const fixedDelayMs = parseInt(input.fixedDelayMs || '5000', 10);

// --- GitHub REST helper with retry/rate-limit ---
function _rawRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const bodyStr = body ? JSON.stringify(body) : '';
    const headers = {
      'Authorization': `Bearer ${token}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'X-GitHub-Api-Version': '2022-11-28'
    };
    if (body) {
      headers['Content-Type'] = 'application/json';
      headers['Content-Length'] = Buffer.byteLength(bodyStr);
    }
    const req = https.request({ hostname: 'api.github.com', path, method, headers }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => {
        let parsed;
        try { parsed = JSON.parse(d); } catch(e) { parsed = d; }
        resolve({ status: res.statusCode, data: parsed, headers: res.headers });
      });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

async function githubRest(method, path, body, maxRetries = 3) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const result = await _rawRequest(method, path, body);
    if (result.status >= 200 && result.status < 300) return result;
    if (result.status === 403 || result.status === 429) {
      const retryAfter = result.headers['retry-after'];
      const rateLimitReset = result.headers['x-ratelimit-reset'];
      let waitMs;
      if (retryAfter) waitMs = parseInt(retryAfter, 10) * 1000;
      else if (rateLimitReset) waitMs = Math.max((parseInt(rateLimitReset, 10) * 1000) - Date.now(), 1000);
      else waitMs = Math.pow(2, attempt) * 1000;
      if (attempt < maxRetries) { await new Promise(r => setTimeout(r, waitMs)); continue; }
    }
    if (result.status >= 400 && result.status < 500) throw new Error(`GitHub API ${result.status}: ${JSON.stringify(result.data)}`);
    if (result.status >= 500 && attempt < maxRetries) { await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000)); continue; }
    throw new Error(`GitHub API failed after ${maxRetries + 1} attempts: ${result.status}`);
  }
}

// --- LLM call with rate limit awareness ---
async function callLLM(messages, maxRetries = 3) {
  const model = process.env.OPENROUTER_MODEL || $env.OPENROUTER_MODEL || 'stepfun/step-3.5-flash:free';
  const apiKey = process.env.OPENROUTER_API_KEY || $env.OPENROUTER_API_KEY;
  const bodyStr = JSON.stringify({ model, messages, max_tokens: 4096 });

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const result = await new Promise((resolve, reject) => {
      const req = https.request({
        hostname: 'openrouter.ai',
        path: '/api/v1/chat/completions',
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${apiKey}`,
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(bodyStr)
        }
      }, res => {
        let d = '';
        res.on('data', c => d += c);
        res.on('end', () => {
          let parsed;
          try { parsed = JSON.parse(d); } catch(e) { parsed = null; }
          resolve({ status: res.statusCode, data: parsed, raw: d, headers: res.headers });
        });
      });
      req.on('error', reject);
      req.write(bodyStr);
      req.end();
    });

    if (result.status === 200 && result.data?.choices?.[0]?.message?.content) {
      return result.data;
    }

    // Rate limited — check headers, then fixed delay
    if (result.status === 429 || result.status === 503) {
      const retryAfter = result.headers?.['retry-after'];
      let waitMs;
      if (retryAfter) {
        waitMs = parseInt(retryAfter, 10) * 1000;
      } else {
        waitMs = Math.max(fixedDelayMs, Math.pow(2, attempt) * 2000);
      }
      if (attempt < maxRetries) {
        await new Promise(r => setTimeout(r, waitMs));
        continue;
      }
    }

    // Other error — retry with backoff on server errors
    if (result.status >= 500 && attempt < maxRetries) {
      await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 2000));
      continue;
    }

    if (attempt >= maxRetries) {
      throw new Error(`LLM call failed after ${maxRetries + 1} attempts. Status: ${result.status}, Response: ${result.raw?.substring(0, 500)}`);
    }
  }
}

// === Generate detailed story body ===
const storyMessages = [
  {
    role: 'system',
    content: `You are writing a detailed implementation story for the Apeiron Cipher project (Rust/Bevy ECS).\n\nWrite a story body with these sections:\n## Acceptance Criteria\n- (bulleted list)\n\n## Technical Notes\n- (relevant ECS systems, components, data files)\n\n## Implementation Order\nOrder: ${input.storyOrder || 'N/A'}\n\nKeep it concise and actionable. A developer should be able to implement this from the story alone.\n\n## GDD (excerpt)\n${gdd.substring(0, 8000)}\n\n## Project Context (excerpt)\n${projectContext.substring(0, 8000)}`
  },
  {
    role: 'user',
    content: `Epic: ${epicTitle}\nStory: ${storyTitle}\nScope: ${storyDescription}\nDependencies: ${dependencyTitles}\n\n## Epic Scoping Conversation\n${epicComments.substring(0, 4000)}`
  }
];

// Fixed delay before LLM call (respects rate limits between batched calls)
await new Promise(r => setTimeout(r, fixedDelayMs));

const response = await callLLM(storyMessages);
const storyBody = response.choices?.[0]?.message?.content || `## ${storyTitle}\n\n${storyDescription}`;

// === Update the GitHub issue with the detailed body ===
// Fetch current body to preserve dependency/parent footer
const issueData = await githubRest('GET', `/repos/${owner}/${repo}/issues/${storyNumber}`);
const currentBody = issueData.data.body || '';

// Replace the stub placeholder with the real content, keep footer
const stubMarker = '<!-- story-detail-pending -->';
let updatedBody;
if (currentBody.includes(stubMarker)) {
  updatedBody = currentBody.replace(stubMarker, storyBody);
} else {
  // If no marker found, prepend the detailed body
  updatedBody = storyBody + '\n\n' + currentBody;
}

await githubRest('PATCH', `/repos/${owner}/${repo}/issues/${storyNumber}`, { body: updatedBody });

return [{ json: { success: true, storyNumber, storyTitle, detailed: true } }];
